const msg = $json.message || {};
const chat = msg.chat || {};
const from = msg.from || {};

const preguntaOriginal = msg.text || $json.pregunta || "";

const limpiarTexto = (texto) => {
  return String(texto || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[¿?¡!.,;:()\[\]{}\"]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
};

const preguntaNormalizada = limpiarTexto(preguntaOriginal);

const palabras = preguntaNormalizada
  ? preguntaNormalizada.split(" ").filter(Boolean)
  : [];

const codigoUnabMatch = preguntaOriginal.match(/\b[uU]\d{8}\b/);
const idNumericoMatch = preguntaOriginal.match(/\b\d{8,10}\b/);

return [
  {
    json: {
      pregunta_original: preguntaOriginal,
      pregunta_normalizada: preguntaNormalizada,
      palabras,
      longitud_texto: preguntaOriginal.length,
      cantidad_palabras: palabras.length,

      chat_id: chat.id,
      telegram_user_id: from.id,
      username: from.username || null,
      first_name: from.first_name || null,
      last_name: from.last_name || null,

      canal: "telegram",

      codigo_unab_detectado: codigoUnabMatch ? codigoUnabMatch[0].toUpperCase() : null,
      id_estudiante_detectado: idNumericoMatch ? idNumericoMatch[0] : null,
      tiene_codigo_detectado: !!codigoUnabMatch || !!idNumericoMatch,

      fecha_mensaje: new Date().toISOString()
    }
  }
];

const base = $input.first().json;
const p = base.pregunta_normalizada || "";
const palabras = base.palabras || [];

const contexto = {
  es_mensaje_vacio: !p,
  es_mensaje_corto: palabras.length > 0 && palabras.length <= 2,
  posible_saludo: /\b(hola|buenas|buenos dias|buenas tardes|buenas noches|buen dia)\b/.test(p),
  posible_agradecimiento: /\b(gracias|muchas gracias|mil gracias|te agradezco|muy amable)\b/.test(p),
  posible_despedida: /\b(chao|adios|hasta luego|nos vemos|hasta pronto|feliz dia)\b/.test(p),
  posible_prioridad: /\b(urgente|rapido|necesito ya|lo antes posible|emergencia)\b/.test(p),
  menciona_google_calendar: /\b(google calendar|calendar|agenda|agenda ccd|agenda del ccd|actividades del ccd|actividades proximas|actividades próximas|eventos proximos|eventos próximos|proximas actividades|próximas actividades|que actividades hay|qué actividades hay|que eventos hay|qué eventos hay)\b/.test(p),
  menciona_fecha: /\b(cuando|fecha|fechas|calendario|cronograma|inscripcion|inscripciones|inicio|evento|eventos|prueba diagnostica)\b/.test(p),
  menciona_historial: /\b(mis cursos|he tomado|historial|cursos realizados|cursos vistos|avance|mi ruta)\b/.test(p),
  tiene_codigo: base.tiene_codigo_detectado
};

let respuesta_contextual = null;

if (contexto.es_mensaje_vacio) {
  respuesta_contextual = "Claro, con gusto te ayudo. ¿Me puedes escribir tu pregunta sobre el CCD, cursos, calendario, eventos, noticias o ruta CCD?";
} else if (contexto.posible_prioridad && palabras.length <= 4) {
  respuesta_contextual = "Entiendo que es urgente. Cuéntame un poco más para orientarte mejor. También puedes contactar el canal oficial del CCD si necesitas atención administrativa inmediata.";
}

return [
  {
    json: {
      ...base,
      contexto_conversacional: contexto,
      respuesta_contextual
    }
  }
];

const p = $json.pregunta_normalizada || "";
const palabras = $json.palabras || [];
const contexto = $json.contexto_conversacional || {};

let intencion = "desconocido";
let respuesta_directa = null;

const incluye = (...terms) => terms.some((term) => p.includes(term));
const esSolo = (...terms) => terms.includes(p);

if (!p || palabras.length === 0) {
  intencion = "desconocido";
  respuesta_directa = $json.respuesta_contextual || "Claro, con gusto te ayudo. ¿Me puedes escribir tu pregunta sobre cursos, calendario, eventos, noticias o ruta CCD?";
} else if (contexto.posible_agradecimiento) {
  intencion = "agradecimiento";
  respuesta_directa = "Con mucho gusto. Si necesitas algo más sobre el CCD, aquí estaré para ayudarte.";
} else if (contexto.posible_despedida || esSolo("chao", "adios", "hasta luego", "nos vemos")) {
  intencion = "despedida";
  respuesta_directa = "Hasta luego. Que tengas un excelente día y muchos éxitos en tu ruta CCD.";
} else if (contexto.posible_saludo || esSolo("hola", "buenas", "buenos dias", "buenas tardes", "buenas noches")) {
  intencion = "saludo";
  respuesta_directa = "Hola, soy el asistente del Centro de Competencias Digitales. Puedo ayudarte con cursos, calendario, eventos, noticias, ruta CCD, certificaciones o tu historial académico.";
} else if (contexto.posible_prioridad && palabras.length <= 4) {
  intencion = "desconocido";
  respuesta_directa = $json.respuesta_contextual;
} else if (incluye("que es el ccd", "centro de competencias digitales")) {
  intencion = "faq_directa";
  respuesta_directa = "El Centro de Competencias Digitales, CCD, acompaña el fortalecimiento de habilidades digitales en la comunidad universitaria mediante cursos y recursos sobre cultura digital, analítica, contenido digital y tecnologías transformativas.";
} else if (incluye("ruta de competencias digitales", "competencias digitales")) {
  intencion = "faq_directa";
  respuesta_directa = "La Ruta de Competencias Digitales está organizada por pilares de formación como Competencias Digitales Básicas, Analítica y Contenido Digital, y Tecnologías Transformativas.";
} else if (incluye("cuantos cursos", "cuantos debo tomar", "que cursos debo tomar", "cursos obligatorios")) {
  intencion = "faq_directa";
  respuesta_directa = "La ruta contempla un curso base de competencias digitales y cursos complementarios según el avance definido por el CCD. Para requisitos o certificación, puedo consultar la base documental.";
} else if (contexto.menciona_google_calendar) {
  intencion = "calendario_google";
} else if (contexto.menciona_fecha) {
  intencion = "calendario";
} else if (contexto.menciona_historial || contexto.tiene_codigo) {
  intencion = "cursos_estudiante";
} else if (incluye("noticias", "convocatorias", "nuevos cursos", "novedades", "actualidad")) {
  intencion = "noticias";
} else if (incluye("oferta", "cursos disponibles", "catalogo", "analitica", "contenido digital", "tecnologias transformativas", "ia generativa", "inteligencia artificial")) {
  intencion = "oferta_cursos";
} else if (incluye("insignia", "certificacion", "certificado", "ruta ccd", "certificacion ccd", "documento", "requisito", "requisitos")) {
  intencion = "rag_documentos";
}

return [
  {
    json: {
      ...$json,
      intencion,
      respuesta_directa
    }
  }
];

const base = $input.first().json;

return [
  {
    json: {
      ...base,
      respuesta: base.respuesta_directa || "Con gusto. Puedo ayudarte con información del Centro de Competencias Digitales CCD."
    }
  }
];

const base = $('Code - Detectar intención avanzada').first().json;
const eventos = $input.all().map((i) => i.json).filter((e) => e.evento);

let respuesta;

if (eventos.length === 0) {
  respuesta = "Por ahora no encontré eventos registrados en la base del calendario CCD. Puedes consultarme por eventos próximos del Google Calendar si está configurado.";
} else {
  respuesta = "Encontré estos registros del calendario CCD:\n\n" + eventos.map((e) => {
    let linea = `• ${e.evento} (${e.fecha_inicio || "fecha por confirmar"})`;
    if (e.fecha_fin) linea += ` al ${e.fecha_fin}`;
    if (e.descripcion) linea += `\n  ${e.descripcion}`;
    return linea;
  }).join("\n\n");
}

return [
  {
    json: {
      ...base,
      respuesta,
      fuente_respuesta: "postgres_calendario"
    }
  }
];

const base = $('Code - Detectar intención avanzada').first().json;
const eventos = $input.all().map(i => i.json).filter(e => e.summary || e.id);

const formatearFechaHora = (valor) => {
  if (!valor) return "fecha por confirmar";

  const fecha = new Date(valor);
  if (isNaN(fecha.getTime())) return String(valor);

  return fecha.toLocaleString("es-CO", {
    timeZone: "America/Bogota",
    year: "numeric",
    month: "long",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit"
  });
};

let respuesta;

if (eventos.length === 0) {
  respuesta =
    `Por ahora no encontré eventos próximos en el calendario del CCD. 📅\n\n` +
    `Puedes volver a consultarme más adelante para revisar nuevas actividades.`;
} else {
  respuesta =
    `Estos son los próximos eventos registrados en el calendario del CCD 📅:\n\n` +
    eventos.map((e) => {
      const titulo = e.summary || "Evento sin título";
      const inicio = e.start?.dateTime || e.start?.date;
      const fin = e.end?.dateTime || e.end?.date;

      let linea = `• ${titulo}\n  Inicio: ${formatearFechaHora(inicio)}`;

      if (fin) {
        linea += `\n  Fin: ${formatearFechaHora(fin)}`;
      }

      if (e.location) {
        linea += `\n  Lugar: ${e.location}`;
      }

      if (e.htmlLink) {
        linea += `\n  Enlace: ${e.htmlLink}`;
      }

      return linea;
    }).join("\n\n") +
    `\n\nSi quieres, también puedo ayudarte a revisar cursos disponibles o información de la ruta CCD.`;
}

return [
  {
    json: {
      ...base,
      respuesta,
      fuente_respuesta: "google_calendar"
    }
  }
];

const base = $('Code - Detectar intención avanzada').first().json;
const cursos = $input.all().map((i) => i.json).filter((c) => c.nombre);

let respuesta;

if (cursos.length === 0) {
  respuesta = "En este momento no encontré cursos activos registrados en la base del CCD.";
} else {
  const grupos = cursos.reduce((acc, curso) => {
    const categoria = curso.categoria || "Sin categoría";
    acc[categoria] = acc[categoria] || [];
    acc[categoria].push(curso.nombre);
    return acc;
  }, {});

  respuesta = "Esta es la oferta de cursos CCD que encontré:\n\n" + Object.entries(grupos).map(([categoria, nombres]) => {
    return `${categoria}:\n${nombres.map((nombre) => `• ${nombre}`).join("\n")}`;
  }).join("\n\n");
}

return [{ json: { ...base, respuesta } }];

const base = $input.first().json;

return [
  {
    json: {
      ...base,
      codigo_unab: base.codigo_unab_detectado,
      id_estudiante: base.id_estudiante_detectado,
      tiene_codigo: base.tiene_codigo_detectado
    }
  }
];

const base = $input.first().json;

return [
  {
    json: {
      ...base,
      respuesta:
        `Claro 😊 Para consultar tus cursos realizados necesito validar tu información.\n\n` +
        `Por favor envíame tu código UNAB o tu ID de estudiante.\n\n` +
        `Ejemplos:\n` +
        `• U00175325\n` +
        `• 20240005\n\n` +
        `Cuando me lo envíes, reviso tus cursos registrados en el CCD.`,
      estado_conversacion: "pendiente_codigo_estudiante",
      fuente_respuesta: "solicitud_codigo_estudiante"
    }
  }
];

const base = $('Code - Verificar codigo estudiante').first().json;
const cursos = $input.all().map((i) => i.json).filter((c) => c.nombre_materia);

let respuesta;

if (cursos.length === 0) {
  respuesta = "No encontré cursos registrados para el código indicado. Revisa que el código esté bien escrito o intenta con tu ID de estudiante.";
} else {
  const estudiante = cursos[0];
  respuesta = `Encontré estos cursos CCD registrados para ${estudiante.nombre_completo}:\n\n` + cursos.map((c) => `• ${c.nombre_materia} (${c.semestre || "semestre no registrado"})`).join("\n");
}

return [{ json: { ...base, respuesta } }];

const base = $('Code - Detectar intención avanzada').first().json;
const noticias = $input.all().map((n) => n.json).filter((n) => n.titulo);

let respuesta;

if (noticias.length === 0) {
  respuesta = "Por ahora no encontré noticias disponibles en la base del CCD.";
} else {
  respuesta = "Estas son las noticias más recientes que encontré:\n\n" + noticias.map((n) => `• ${n.titulo}${n.fecha_publicacion ? ` (${n.fecha_publicacion})` : ""}${n.enlace ? `\n  ${n.enlace}` : ""}`).join("\n");
}

return [{ json: { ...base, respuesta } }];

const base = $input.first().json;

return [
  {
    json: {
      ...base,
      query_rag: base.pregunta_original
    }
  }
];

const base = $('Code - Detectar intención avanzada').first().json;
const chunks = $input.all().map((i) => i.json).filter((r) => r.chunk_text);

let contexto = chunks.map((r, idx) => {
  const titulo = r.nombre_documento || r.metadata?.nombre_documento || r.metadata?.titulo || `Documento ${idx + 1}`;
  const categoria = r.categoria || r.metadata?.categoria || "CCD";
  return `Categoría: ${categoria}\nTítulo: ${titulo}\nContenido:\n${r.chunk_text}`;
}).join("\n\n---\n\n");

if (!contexto || contexto.trim().length === 0) {
  contexto = "No se encontraron fragmentos relevantes en la base documental.";
}

return [{ json: { ...base, contexto } }];

