const base = $('Code - Armar contexto RAG').first().json;
const respuesta = $json.choices?.[0]?.message?.content || $json.output_text || $json.text || $json.response || "No pude generar una respuesta con la información disponible.";

return [{ json: { ...base, respuesta } }];

const base = $input.first().json;

return [
  {
    json: {
      ...base,
      respuesta: base.respuesta_directa || "Por ahora no tengo suficiente información para responder eso con seguridad. Puedes preguntarme sobre cursos, calendario, eventos, noticias, certificación o tu historial académico."
    }
  }
];

const base = $input.first().json;

let respuesta = base.respuesta || base.respuesta_directa || "";

if (!respuesta.trim()) {
  respuesta =
    `Lo siento, no pude generar una respuesta con la información disponible. 😊\n\n` +
    `Puedes intentar reformular tu pregunta o consultarme sobre cursos, calendario, eventos, noticias o ruta CCD.`;
}

const limite = 3500;

if (respuesta.length > limite) {
  respuesta = respuesta.slice(0, limite) + "\n\n...Respuesta resumida por límite de longitud.";
}

const cierres = [
  "puedo ayudarte",
  "también puedo ayudarte",
  "aquí estaré",
  "con gusto"
];

const tieneCierre = cierres.some(c => respuesta.toLowerCase().includes(c));

if (!tieneCierre && !["agradecimiento", "despedida"].includes(base.intencion)) {
  respuesta += "\n\nSi necesitas, también puedo ayudarte con otra consulta del CCD.";
}

return [
  {
    json: {
      ...base,
      respuesta_final: respuesta,
      respuesta
    }
  }
];
